import type SubtypeGroupLayer from "../../layers/SubtypeGroupLayer.js";
import type FeatureLikeLayerView from "./FeatureLikeLayerView.js";

/**
 * Represents the [LayerView](https://developers.arcgis.com/javascript/latest/references/core/views/layers/LayerView/) of a [SubtypeGroupLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/SubtypeGroupLayer/)
 * after it has been added to a [Map](https://developers.arcgis.com/javascript/latest/references/core/Map/).
 *
 * The SubtypeGroupLayerView is responsible for rendering a [SubtypeGroupLayer's](https://developers.arcgis.com/javascript/latest/references/core/layers/SubtypeGroupLayer/)
 * features as [graphics](https://developers.arcgis.com/javascript/latest/references/core/Graphic/) in the [View](https://developers.arcgis.com/javascript/latest/references/core/views/View/).
 *
 * @since 4.16
 * @see [SubtypeGroupLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/SubtypeGroupLayer/)
 */
export default abstract class SubtypeGroupLayerView extends FeatureLikeLayerView {
  /** The layer being viewed. */
  get layer(): SubtypeGroupLayer;
}